import{_ as n,o as a,c as p,a2 as l}from"./chunks/framework.BKchhTkY.js";const r=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"guide/other/dwt使用.md","filePath":"guide/other/dwt使用.md","lastUpdated":1783672098000}'),e={name:"guide/other/dwt使用.md"};function i(c,s,t,o,d,_){return a(),p("div",null,[...s[0]||(s[0]=[l(`<div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  DWT 在 ARM Cortex-M 中是一个完整的调试/跟踪模块，包含以下功能：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ┌─────────────────┬─────────────────────────────┬───────────────────────┐</span></span>
<span class="line"><span>  │      功能       │            说明             │    本文件是否使用     │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ CYCCNT          │ 周期计数器（每CPU时钟+1）   │ 是 — 全部接口都基于它 │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ DWT_COMPn       │ 数据监视点/硬件断点（0~15） │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ Exception Trace │ 异常进出跟踪                │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ PC Sampling     │ 周期性PC采样                │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ FOLDCNT         │ 折叠指令计数器              │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ LSUCNT          │ Load/Store 操作计数器       │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ SLEEPCNT        │ 睡眠周期计数器              │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ EXCCNT          │ 异常开销周期计数器          │ 否                    │</span></span>
<span class="line"><span>  ├─────────────────┼─────────────────────────────┼───────────────────────┤</span></span>
<span class="line"><span>  │ CPICNT          │ 每指令周期数计数器          │ 否                    │</span></span>
<span class="line"><span>  └─────────────────┴─────────────────────────────┴───────────────────────┘</span></span></code></pre></div><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>❯ 怎么保证两次调用DWT_CNT_Update之间的时间间隔不超过一次溢出</span></span>
<span class="line"><span></span></span>
<span class="line"><span>● 这是这个模块的一个设计约束，目前没有强制保证机制，依赖的是使用者的调用频率。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  数学上的硬限制</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  CYCCNT 是 32 位寄存器，168MHz 下溢出周期约 25.5 秒。如果两次 DWT_CNT_Update() 间隔超过这个时间，光凭 cnt_now &lt; s_cyccnt_last 无法判断溢出了 1 次还是 N 次——这是 32 位计数器扩展成</span></span>
<span class="line"><span>   64 位的先天缺陷，无法修复。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  当前实际状态：靠使用模式保证</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  所有 DWT_GetTimeUs() 的调用者运行频率都很高：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  ┌───────────────────────────────────────────┬────────────┬────────┐</span></span>
<span class="line"><span>  │                  调用者                   │  典型频率  │  间隔  │</span></span>
<span class="line"><span>  ├───────────────────────────────────────────┼────────────┼────────┤</span></span>
<span class="line"><span>  │ 电机反馈 (drv_dmmotor/djimotor)           │ 1kHz       │ 1ms    │</span></span>
<span class="line"><span>  ├───────────────────────────────────────────┼────────────┼────────┤</span></span>
<span class="line"><span>  │ APP 任务看门狗 (motor/chassis/cmd/sensor) │ 100Hz~1kHz │ 1~10ms │</span></span>
<span class="line"><span>  ├───────────────────────────────────────────┼────────────┼────────┤</span></span>
<span class="line"><span>  │ 编码器测速 (bsp_tim)                      │ 控制循环内 │ &lt;10ms  │</span></span>
<span class="line"><span>  ├───────────────────────────────────────────┼────────────┼────────┤</span></span>
<span class="line"><span>  │ Daemon 任务                               │ 1kHz       │ 1ms    │</span></span>
<span class="line"><span>  ├───────────────────────────────────────────┼────────────┼────────┤</span></span>
<span class="line"><span>  │ CAN 超时轮询                              │ while 循环 │ &lt;1μs   │</span></span>
<span class="line"><span>  ├───────────────────────────────────────────┼────────────┼────────┤</span></span>
<span class="line"><span>  │ BMI088 SPI 时间戳                         │ 1kHz       │ 1ms    │</span></span>
<span class="line"><span>  └───────────────────────────────────────────┴────────────┴────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  全部远低于 25 秒阈值，实际上不会触发多重溢出。但如果将来有人写了一个低频任务调用 DWT_GetTimeUs()（比如每 30 秒一次），时间轴就会跳变。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  怎么加固</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  最稳妥的做法是在 SysTick 中断里定期调用 DWT_CNT_Update()（不一定是完整的 DWT_GetTimeUs，只需要溢出检查）。FreeRTOS 的 1kHz tick 已经足够。可以在 bsp_dwt.c 暴露一个轻量接口：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  // 供 SysTick/Timer ISR 调用的轻量版本，仅做溢出检测</span></span>
<span class="line"><span>  void DWT_CNT_Update(void);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  然后在 HAL_SYSTICK_Callback() 或 RTOS 的 tick hook 中调用它，保证即使在没有任何用户代码调用 DWT_GetTimeUs() 的极限情况下，溢出也能被记录。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  需要我加上这个 SysTick hook 吗？</span></span></code></pre></div>`,2)])])}const m=n(e,[["render",i]]);export{r as __pageData,m as default};
